type AuthInterceptor struct {
}

func (a *AuthInterceptor) UnaryInterceptor(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
	// Extract metadata from incoming context
	md, ok := metadata.FromIncomingContext(ctx)
	if !ok {
		return nil, status.Error(codes.Unauthenticated, "missing metadata")
	}

	// Get authorization header
	authHeaders := md.Get(authHeaderKey)
	if len(authHeaders) == 0 {
		return nil, status.Error(codes.Unauthenticated, "missing authorization header")
	}

	// Validate token
	token := authHeaders[0]
	if !a.validateToken(token) {
		return nil, status.Error(codes.Unauthenticated, "invalid token")
	}

	// Add peer information to context for logging
	if p, ok := peer.FromContext(ctx); ok {
		ctx = context.WithValue(ctx, "peer_addr", p.Addr.String())
	}

	// Continue with the request
	return handler(ctx, req)
}

func (a *AuthInterceptor) validateToken(token string) bool {
	// Check if token starts with Bearer prefix
	if !isBearerToken(token) {
		return false
	}

	// Extract actual token
	actualToken := token[len(bearerPrefix):]
	
	// Use constant time comparison to prevent timing attacks
	// This is important for security
	for validToken := range validTokens {
		if subtle.ConstantTimeCompare([]byte(actualToken), []byte(validToken)) == 1 {
			return true
		}
	}
	
	return false
}

func isBearerToken(token string) bool {
	return len(token) > len(bearerPrefix) && 
		   token[:len(bearerPrefix)] == bearerPrefix
}

